// ═══════════════════════════════════════════════════════
//  RETRIEVAL ENGINE (TF-IDF-like keyword matching)
// ═══════════════════════════════════════════════════════

/**
 * Retrieve the most relevant knowledge chunks for a query.
 * Uses keyword overlap scoring with category/topic boosting.
 * 
 * @param {string} query - User's question
 * @param {number} topK - Number of chunks to return (default 5)
 * @returns {Array} Top matching chunks with relevance scores
 */
export function retrieveKnowledge(query, topK = 5) {
  if (!query || query.trim().length === 0) return [];

  // Normalize and tokenize query
  const queryTokens = query.toLowerCase()
    .replace(/[^a-z0-9\s]/g, ' ')
    .split(/\s+/)
    .filter(t => t.length > 2);

  // Remove common stop words
  const stopWords = new Set([
    'the', 'and', 'for', 'are', 'but', 'not', 'you', 'all', 'can', 'had',
    'has', 'was', 'one', 'our', 'how', 'what', 'when', 'where', 'which',
    'who', 'why', 'will', 'with', 'this', 'that', 'from', 'they', 'been',
    'have', 'does', 'its', 'about', 'would', 'there', 'their', 'than',
    'them', 'then', 'these', 'some', 'her', 'him', 'his', 'she', 'also',
    'just', 'more', 'very', 'much', 'should', 'could', 'need', 'want',
    'tell', 'give', 'know', 'like', 'help', 'please', 'make',
  ]);
  const queryKeywords = queryTokens.filter(t => !stopWords.has(t));

  if (queryKeywords.length === 0) return [];

  // Score each chunk
  const scored = KNOWLEDGE_BASE.map(chunk => {
    let score = 0;
    const allText = (chunk.content + ' ' + chunk.topic).toLowerCase();

    // Keyword match scoring
    for (const keyword of queryKeywords) {
      // Direct keyword array match (highest weight)
      if (chunk.keywords.includes(keyword)) {
        score += 3;
      }
      // Topic match (high weight)
      if (chunk.topic.toLowerCase().includes(keyword)) {
        score += 2;
      }
      // Category match
      if (chunk.category.toLowerCase().includes(keyword)) {
        score += 1.5;
      }
      // Content body match (count occurrences, capped)
      const regex = new RegExp(`\\b${keyword.replace(/[.*+?^${}()|[\]\\]/g, '\\$&')}`, 'gi');
      const matches = allText.match(regex);
      if (matches) {
        score += Math.min(matches.length, 3); // Cap at 3 per keyword
      }
    }

    // Bonus for exact multi-word phrase match
    const queryLower = query.toLowerCase();
    if (queryLower.length > 5) {
      if (chunk.topic.toLowerCase().includes(queryLower)) {
        score += 15;
      }
      if (chunk.content.toLowerCase().includes(queryLower)) {
        score += 8;
      }
    }

    // Bonus for matching multiple keywords (relevance boost)
    const matchedKeywords = queryKeywords.filter(kw => chunk.keywords.includes(kw));
    if (matchedKeywords.length >= 3) score += 5;
    if (matchedKeywords.length >= 5) score += 10;

    return { ...chunk, score };
  });

  // Sort by score descending, return top K
  return scored
    .filter(c => c.score > 0)
    .sort((a, b) => b.score - a.score)
    .slice(0, topK)
    .map(({ score, ...chunk }) => ({ ...chunk, relevance: score }));
}

/**
 * Format retrieved chunks into a context string for the LLM prompt.
 */
export function formatRAGContext(chunks) {
  if (!chunks || chunks.length === 0) return '';

  const stats = getKnowledgeStats();
  const formatted = chunks.map((c, i) =>
    `[Source ${i + 1}: ${c.category} — ${c.topic} (Relevance: ${c.relevance})]:\n${c.content}`
  ).join('\n\n');

  return `\n--- AGRICULTURAL KNOWLEDGE BASE (RAG — ${chunks.length} retrieved from ${stats.total_chunks} total chunks, ${Object.keys(stats.categories).length} categories, ${stats.source_documents} source documents) ---\n${formatted}\n---`;
}

/**
 * Get total chunk count
 */
export function getTotalChunks() {
  return KNOWLEDGE_BASE.length;
}

/**
 * Get all categories with chunk counts + source document info
 */
export function getKnowledgeStats() {
  const stats = {};
  const sources = new Set();
  for (const chunk of KNOWLEDGE_BASE) {
    stats[chunk.category] = (stats[chunk.category] || 0) + 1;
    if (chunk.source) sources.add(chunk.source);
  }
  return {
    total_chunks: KNOWLEDGE_BASE.length,
    categories: stats,
    topics: [...new Set(KNOWLEDGE_BASE.map(c => c.topic))].length,
    source_documents: sources.size,
    sources: [...sources],
  };
}

export default { retrieveKnowledge, formatRAGContext, getTotalChunks, getKnowledgeStats, KNOWLEDGE_BASE };
